": "procedure", "data_complexity": "pathology review", "total_time_minutes": 0, "separate_procedure_same_day": false}, "procedures": [{"text": "3 mm punch biopsy of the right nasal ala lesion", "views": 0, "anatomy": "right nasal ala", "contrast": "n/a", "line_end": 3, "modality": "", "laterality": "right", "line_start": 3}]}, {"stage": "rag", "title": "Graph-RAG Retrieval", "learned": [], "icd_candidates": [{"code": "C44.91", "age_max": 130, "age_min": 0, "billable": true, "description": "Basal cell carcinoma of skin, unspecified", "sex_restriction": ""}, {"code": "D48.5", "age_max": 130, "age_min": 0, "billable": true, "description": "Neoplasm of uncertain behavior of skin", "sex_restriction": ""}, {"code": "C44.9", "age_max": 130, "age_min": 0, "billable": false, "description": "Other and unspecified malignant neoplasm of skin, unspecified", "sex_restriction": ""}], "ontology_paths": [{"edges": [], "concept": "Skin structure", "maps_to": [], "semantic_type": "Body Part"}, {"edges": [{"to": "Skin structure", "rel": "finding_site"}], "concept": "Basal cell carcinoma", "maps_to": [{"code": "C44.91", "system": "ICD10CM"}], "semantic_type": "Neoplastic Process"}], "payer_policies": [{"code": "57454", "payer": "Medicare", "covered_dx": ["N87", "R87"], "modifier_pref": "", "requires_auth": false, "medical_necessity": "Colposcopy with cervical biopsy covered for abnormal cervical cytology or documented dysplasia."}, {"code": "45385", "payer": "Medicare", "covered_dx": ["K63", "Z12", "K57"], "modifier_pref": "", "requires_auth": false, "medical_necessity": "Colonoscopy with polypectomy covered for polyp, GI bleeding, or screening findings; report the most extensive technique performed."}, {"code": "43239", "payer": "Medicare", "covered_dx": ["K21", "K29", "K25"], "modifier_pref": "", "requires_auth": false, "medical_necessity": "EGD with biopsy covered for dyspepsia, reflux, or suspected mucosal disease requiring tissue diagnosis."}, {"code": "17000", "payer": "Medicare",